@import url('https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;900&display=swap');

.root_element {
  width: 100%;
}
.block {
  width: 100%;
}
.page-body, .workspace-sidebar-toggle ~ .page-container .container,
.page-container .container,
.layout-main-section-wrapper,
.codex-editor,
.codex-editor__redactor,
.ce-block,
.ce-block__content,
.ce-toolbar__content {
  max-width: 100% !important;
}
.block, .block * {
  box-sizing: border-box;
  font-family:'Tajawal', sans-serif;
}
.block {
  position: relative;
  background: linear-gradient(135deg, #0d3b36 0%, #145048 55%, #0d3b36 100%);
  border-radius: 18px;
  padding: 46px 50px;
  overflow: hidden;
  color: #f4ead9;
  box-shadow: 0 8px 28px rgba(13,59,54,.25);
  transition: box-shadow .3s ease;
}
.block:hover {
  box-shadow: 0 12px 36px rgba(13,59,54,.35);
}
.pattern {
  position:absolute; inset:0;
  background-image:
    repeating-linear-gradient(45deg, rgba(212,175,99,.07) 0, rgba(212,175,99,.07) 1px, transparent 1px, transparent 26px),
    repeating-linear-gradient(-45deg, rgba(212,175,99,.07) 0, rgba(212,175,99,.07) 1px, transparent 1px, transparent 26px);
  pointer-events:none;
}
.gold-ring {
  position:absolute; left:-60px; top:-60px;
  width:220px; height:220px;
  border:1.5px solid rgba(212,175,99,.35);
  border-radius:50%;
  transition: transform .6s ease;
}
.block:hover .gold-ring { transform: rotate(25deg); }
.gold-ring.small {
  left:-20px; top:30px;
  width:120px; height:120px;
  border-color: rgba(212,175,99,.25);
}
.block:hover .gold-ring.small { transform: rotate(-25deg); }

.topbar {
  position: relative;
  z-index: 2;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
  margin-bottom: 24px;
  flex-wrap: wrap;
}
.topbar-left {
  display: flex;
  align-items: center;
}
.topbar-left .logo {
  height: 52px;
  width: auto;
  object-fit: contain;
  filter: drop-shadow(0 2px 6px rgba(0,0,0,.25));
}
.topbar-right {
  text-align: left;
  direction: rtl;
}
.topbar-right .greeting {
  font-size: 16px;
  font-weight: 700;
  color: #f4ead9;
}
.topbar-right .greeting::before {
  content: '👋 ';
}
.topbar-right .datetime {
  font-size: 13px;
  color: #b9d6cd;
  margin-top: 4px;
  opacity: .9;
}

.content {
  position:relative; z-index:2;
  display:flex; align-items:center; justify-content:space-between;
  gap:30px; flex-wrap:wrap;
}
.eyebrow {
  display:inline-flex; align-items:center; gap:8px;
  font-size:13px; letter-spacing:.5px; color:#d4af63;
  border:1px solid rgba(212,175,99,.4);
  padding:5px 14px; border-radius:30px;
  margin-bottom:16px;
  transition: background .2s ease;
}
.eyebrow:hover { background: rgba(212,175,99,.12); }
.eyebrow::before { content:'◆'; font-size:9px; }
.block h1 { font-size:30px; font-weight:900; line-height:1.4; margin-bottom:8px; color:#f4ead9; }
.block h1 span { color:#d4af63; }
.block p.sub { font-size:15px; color:#cfe3dd; max-width:520px; line-height:1.9; opacity:.9; margin:0; }
.stats { display:flex; gap:14px; }
.stat {
  background: rgba(255,255,255,.06);
  border:1px solid rgba(212,175,99,.25);
  border-radius:14px;
  padding:18px 24px;
  text-align:center;
  min-width:108px;
  backdrop-filter: blur(2px);
  transition: transform .2s ease, background .2s ease;
}
.stat:hover {
  transform: translateY(-4px);
  background: rgba(255,255,255,.1);
}
.stat .num { font-size:26px; font-weight:900; color:#fff; }
.stat .lbl { font-size:12px; color:#b9d6cd; margin-top:4px; }
.divider {
  height:1px;
  background:linear-gradient(90deg, transparent, rgba(212,175,99,.5), transparent);
  margin:30px 0 0;
}
.links { display:flex; gap:28px; margin-top:22px; flex-wrap:wrap; }
.links a {
  color:#f4ead9; text-decoration:none; font-size:14px; font-weight:500;
  display:flex; align-items:center; gap:8px;
  opacity:.92;
  transition: opacity .2s ease;
}
.links a:hover { opacity:1; color:#d4af63; }
.links a::after { content:'←'; font-size:13px; color:#d4af63; transition:.2s; }
.links a:hover::after { transform:translateX(-4px); }

script:
//========================================
//      AWQAF PREMIUM HERO
//========================================

const greetingElement = root_element.querySelector("#hero-greeting");
const userElement = root_element.querySelector("#user-name");
const timeElement = root_element.querySelector("#hero-time");
const dateElement = root_element.querySelector("#hero-date");

//========================================
// اسم المستخدم
//========================================

let fullName = "";

if (frappe.session && frappe.session.user_fullname) {
    fullName = frappe.session.user_fullname;
} else if (frappe.boot && frappe.boot.user && frappe.boot.user.full_name) {
    fullName = frappe.boot.user.full_name;
} else if (frappe.session && frappe.session.user) {
    fullName = frappe.session.user;
}

userElement.textContent = fullName || "المستخدم";

//========================================
// الأشهر والأيام
//========================================

const months = [
    "يناير",
    "فبراير",
    "مارس",
    "أبريل",
    "مايو",
    "يونيو",
    "يوليو",
    "أغسطس",
    "سبتمبر",
    "أكتوبر",
    "نوفمبر",
    "ديسمبر"
];

const days = [
    "الأحد",
    "الإثنين",
    "الثلاثاء",
    "الأربعاء",
    "الخميس",
    "الجمعة",
    "السبت"
];

//========================================
// تحديث الوقت
//========================================

function updateClock() {

    const now = new Date();

    let hour = now.getHours();
    let minute = String(now.getMinutes()).padStart(2, "0");
    let second = String(now.getSeconds()).padStart(2, "0");

    let displayHour = String(hour).padStart(2, "0");

    timeElement.textContent =
        `${displayHour}:${minute}:${second}`;

    dateElement.innerHTML =
        `${days[now.getDay()]}<br>${now.getDate()} ${months[now.getMonth()]} ${now.getFullYear()}`;

    //------------------------------------
    // الترحيب حسب الوقت
    //------------------------------------

    let greeting = "";

    if (hour >= 5 && hour < 12) {

        greeting = "🌅 صباح الخير";

    }

    else if (hour >= 12 && hour < 17) {

        greeting = "☀️ طاب يومكم";

    }

    else if (hour >= 17 && hour < 21) {

        greeting = "🌇 مساء الخير";

    }

    else {

        greeting = "🌙 أسعد الله مساءكم";

    }

    greetingElement.textContent = greeting;

}

updateClock();

setInterval(updateClock, 1000);

//========================================
// تأثير بسيط عند تحريك الماوس
//========================================

const hero = root_element.querySelector(".awqaf-premium");

hero.addEventListener("mousemove", function(e) {

    const rect = hero.getBoundingClientRect();

    const x = e.clientX - rect.left;

    const y = e.clientY - rect.top;

    hero.style.backgroundPosition =
        `${50 + (x - rect.width / 2) / 40}% ${50 + (y - rect.height / 2) / 40}%`;

});

hero.addEventListener("mouseleave", function() {

    hero.style.backgroundPosition = "center";

});

