script:
/*
  ============================================================
  dashboard-script.js
  ------------------------------------------------------------
  الصق هذا الكود بالكامل في حقل "Script" الخاص بنفس الـ Custom
  HTML Block (وليس داخل حقل الـ HTML). Frappe يمرر متغيّر
  root_element جاهزًا لهذا الحقل، ولذلك ينفَّذ فعليًا بعكس أي
  <script> يوضع داخل محتوى الـ HTML نفسه.
  ============================================================
*/

function setNum(sel, value) {
  var el = root_element.querySelector(sel + ' .tq-count-value');
  if (el) {
    el.classList.remove('is-loading');
    el.textContent = (typeof value === 'number') ? value.toLocaleString('ar') : '0';
  }
}

/* ─── قسم الوعاظ ─── */
frappe.db.count('waed_info', { filters: { waed_status: 'New' } }).then(function (count) {
  setNum('#stat-waed-new', count);
});

frappe.db.count('waed_info', { filters: { waed_status: 'referred for the exam' } }).then(function (count) {
  setNum('#stat-waed-referred', count);
});

frappe.db.count('exam_group_date').then(function (count) {
  setNum('#stat-exam-groups', count);
});

/* ─── قسم الامتحانات ─── */
frappe.db.count('exam_group_date', { filters: { exam_status: 'Scheduled' } }).then(function (count) {
  setNum('#stat-exam-scheduled', count);
});

/* "قيد الإجراء" تجمع حالتين (كتابي أو شفوي) عبر عامل in بدل OR */
frappe.db.count('exam_group_date', {
  filters: { exam_status: ['in', ['Written In Progress', 'Oral In Progress']] }
}).then(function (count) {
  setNum('#stat-exam-inprogress', count);
});

frappe.db.count('exam_group_date', { filters: { exam_status: 'Completed' } }).then(function (count) {
  setNum('#stat-exam-completed', count);
});

/* ─── جعل بطاقات الإحصاء قابلة للنقر (تنقل لنفس صفحة القائمة المفلترة) ─── */
function goToList(sel, doctype, filters) {
  var el = root_element.querySelector(sel);
  if (!el) return;
  el.style.cursor = 'pointer';
  el.addEventListener('click', function (e) {
    e.preventDefault();
    frappe.set_route('list', doctype, filters || {});
  });
}

goToList('#stat-waed-new', 'waed_info', { waed_status: 'New' });
goToList('#stat-waed-referred', 'waed_info', { waed_status: 'referred for the exam' });
goToList('#stat-exam-groups', 'exam_group_date');
goToList('#stat-exam-scheduled', 'exam_group_date', { exam_status: 'Scheduled' });
goToList('#stat-exam-inprogress', 'exam_group_date', { exam_status: ['in', ['Written In Progress', 'Oral In Progress']] });
goToList('#stat-exam-completed', 'exam_group_date', { exam_status: 'Completed' });

/* ─── روابط أدوات الوعاظ ─── */
function goToListLink(sel, doctype, filters) {
  var el = root_element.querySelector(sel);
  if (!el) return;
  el.addEventListener('click', function (e) {
    e.preventDefault();
    frappe.set_route('list', doctype, filters || {});
  });
}

goToListLink('#link-waed-new', 'waed_info', { waed_status: 'New' });
goToListLink('#link-waed-scheduled', 'waed_info', { waed_status: 'Scheduling an appointment' });
goToListLink('#link-waed-exam-set', 'waed_info', { waed_status: 'referred for the exam' });
goToListLink('#link-waed-passed', 'waed_info', { waed_status: 'Successful in the written exam' });
goToListLink('#link-waed-failed', 'waed_info', { waed_status: 'Rejected' });
goToListLink('#link-waed-approved', 'waed_info', { waed_status: 'Approved' });

/* ─── روابط أدوات الامتحانات (صفحات/نماذج جديدة، وليست قوائم) ─── */
function goToRoute(sel) {
  var el = root_element.querySelector(sel);
  if (!el) return;
  el.addEventListener('click', function (e) {
    e.preventDefault();
    frappe.set_route(this.getAttribute('href').replace(/^\/app\//, ''));
  });
}

goToRoute('#link-exam-create');
goToRoute('#link-exam-date-create');
goToRoute('#link-exam-grading');
goToRoute('#link-exam-approve');

