@import url('https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;900&display=swap');

/*
  ============================================================
  dashboard.css - لوحة "قسم الوعاظ" الأكاديمية
  Frappe v15 Workspace - Custom HTML Block
  ------------------------------------------------------------
  تنسيق فقط، لا يحتوي أي منطق أو ربط بيانات.
  الألوان معتمدة على هوية أخضر داكن + ذهبي (نفس هوية الهيدر
  المرسل: #0d3b36 / #145048 / #d4af63 / #f4ead9).
  ============================================================
*/

.tq-dash {
  --tq-bg:            #ffffff;
  --tq-surface:       #f8faf9;
  --tq-border:        #e1e9e6;
  --tq-border-soft:   #edf3f1;

  --tq-ink:           #10281f;
  --tq-ink-soft:      #5c6f68;
  --tq-ink-faint:     #8a9a94;

  /* الأخضر الداكن (اللون الأساسي الجديد) */
  --tq-accent:        #145048;
  --tq-accent-dark:   #0d3b36;
  --tq-accent-soft:   #e8f1ee;
  --tq-accent-ring:   rgba(20, 80, 72, 0.16);

  /* الذهبي (لون ثانوي/تمييز) */
  --tq-gold:          #b8923f;
  --tq-gold-soft:     #faf5e9;

  --tq-emerald:       #1f7a5c;
  --tq-emerald-soft:  #e9f6f0;

  --tq-amber:         #b3791f;
  --tq-amber-soft:    #fbf1e2;

  --tq-red:           #b23a3a;
  --tq-red-soft:      #fbeceb;

  --tq-grey:          #5a6474;
  --tq-grey-soft:     #eef0f3;

  /* ألوان الهيدر (Hero) الداكن */
  --tq-hero-start:    #0d3b36;
  --tq-hero-end:      #145048;
  --tq-cream:         #f4ead9;
  --tq-cream-soft:    #cfe3dd;

  --tq-radius-sm: 10px;
  --tq-radius-md: 14px;
  --tq-radius-lg: 18px;
  --tq-space-1: 6px;
  --tq-space-2: 10px;
  --tq-space-3: 16px;
  --tq-space-4: 24px;
  --tq-space-5: 36px;

  --tq-shadow-sm: 0 1px 2px rgba(13, 59, 54, 0.06);
  --tq-shadow-md: 0 6px 18px rgba(13, 59, 54, 0.08);
  --tq-shadow-lg: 0 14px 32px rgba(13, 59, 54, 0.12);

  --tq-font: "Tajawal", "Segoe UI", "Cairo", "Geeza Pro", Arial, sans-serif;

  display: block;
  box-sizing: border-box;
  font-family: var(--tq-font);
  color: var(--tq-ink);
  background: var(--tq-bg);
  direction: rtl;
  text-align: right;
  line-height: 1.6;
}

.tq-dash *,
.tq-dash *::before,
.tq-dash *::after {
  box-sizing: border-box;
}

.tq-dash :focus-visible {
  outline: 2px solid var(--tq-accent);
  outline-offset: 2px;
  border-radius: var(--tq-radius-sm);
}

@media (prefers-reduced-motion: reduce) {
  .tq-dash * { transition: none !important; animation: none !important; }
}

/* ============================================================
   عناوين الأقسام الرئيسية (قسم الوعاظ / قسم الامتحانات)
   ============================================================ */
.tq-module {
  margin-bottom: var(--tq-space-5);
}

.tq-module__header {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: var(--tq-space-4);
  padding-bottom: var(--tq-space-2);
  border-bottom: 1px solid var(--tq-border-soft);
}

.tq-module__icon {
  flex-shrink: 0;
  width: 38px;
  height: 38px;
  border-radius: 11px;
  background: var(--tq-accent-soft);
  color: var(--tq-accent);
  display: flex;
  align-items: center;
  justify-content: center;
}

.tq-module__icon svg { width: 20px; height: 20px; }

.tq-module__title {
  font-size: 19px;
  font-weight: 800;
  color: var(--tq-ink);
  margin: 0;
}

.tq-module__subtitle {
  font-size: 12.5px;
  color: var(--tq-ink-faint);
  margin: 2px 0 0 0;
}

/* عنوان فرعي داخل القسم (مثل: أدوات الوعاظ / أدوات الامتحانات) */
.tq-subsection-title {
  font-size: 14px;
  font-weight: 700;
  color: var(--tq-ink);
  margin: 0 0 var(--tq-space-3) 0;
  display: flex;
  align-items: center;
  gap: 8px;
}

.tq-subsection-title::before {
  content: "";
  width: 4px;
  height: 14px;
  border-radius: 3px;
  background: var(--tq-gold);
  display: inline-block;
}

.tq-subsection {
  margin-bottom: var(--tq-space-4);
}

.tq-subsection:last-child {
  margin-bottom: 0;
}

/* ============================================================
   الهيدر الرئيسي (Hero) - أخضر داكن + ذهبي
   ============================================================ */
.tq-hero {
  position: relative;
  overflow: hidden;
  border-radius: var(--tq-radius-lg);
  padding: 42px 40px;
  margin-bottom: var(--tq-space-5);
  background: linear-gradient(135deg, var(--tq-hero-start) 0%, var(--tq-hero-end) 55%, var(--tq-hero-start) 100%);
  border: 1px solid rgba(212, 175, 99, 0.2);
  box-shadow: var(--tq-shadow-md);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--tq-space-4);
  color: var(--tq-cream);
}

.tq-hero__pattern {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background-image:
    repeating-linear-gradient(45deg, rgba(212,175,99,.07) 0, rgba(212,175,99,.07) 1px, transparent 1px, transparent 26px),
    repeating-linear-gradient(-45deg, rgba(212,175,99,.07) 0, rgba(212,175,99,.07) 1px, transparent 1px, transparent 26px);
}
.tq-hero__pattern svg { display: none; }

.tq-hero::before,
.tq-hero::after {
  content: "";
  position: absolute;
  border: 1.5px solid rgba(212, 175, 99, 0.3);
  border-radius: 50%;
  pointer-events: none;
}
.tq-hero::before { width: 220px; height: 220px; left: -60px; top: -60px; }
.tq-hero::after { width: 120px; height: 120px; left: -20px; top: 30px; border-color: rgba(212,175,99,.22); }

.tq-hero__content { position: relative; z-index: 1; max-width: 620px; }

.tq-hero__eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: .3px;
  color: var(--tq-gold);
  background: transparent;
  border: 1px solid rgba(212, 175, 99, 0.4);
  padding: 5px 14px;
  border-radius: 999px;
  margin-bottom: 14px;
}
.tq-hero__eyebrow::before { content: "◆"; font-size: 9px; }

.tq-hero__title { font-size: 27px; font-weight: 900; color: var(--tq-cream); margin: 0 0 8px 0; }
.tq-hero__subtitle { font-size: 13.5px; color: var(--tq-cream-soft); margin: 0; max-width: 520px; opacity: .92; line-height: 1.9; }

.tq-hero__seal {
  position: relative;
  z-index: 1;
  flex-shrink: 0;
  width: 84px;
  height: 84px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.06);
  border: 1px solid rgba(212, 175, 99, 0.35);
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: var(--tq-shadow-sm);
}

.tq-hero__seal svg { width: 40px; height: 40px; color: var(--tq-gold); }

/* ============================================================
   بطاقات الإحصاء (Number Cards المقابلة)
   ============================================================ */
.tq-stats {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--tq-space-3);
  margin-bottom: var(--tq-space-4);
}

.tq-stat-card {
  position: relative;
  background: var(--tq-surface);
  border: 1px solid var(--tq-border-soft);
  border-radius: var(--tq-radius-md);
  padding: 16px 18px;
  box-shadow: var(--tq-shadow-sm);
  transition: transform 0.16s ease, box-shadow 0.16s ease, border-color 0.16s ease;
  overflow: hidden;
  text-decoration: none;
  color: inherit;
  display: block;
}

.tq-stat-card::after {
  content: "";
  position: absolute;
  inset-inline-start: 0;
  top: 0;
  bottom: 0;
  width: 4px;
  background: var(--tq-card-accent, var(--tq-accent));
}

.tq-stat-card:hover {
  transform: translateY(-3px);
  box-shadow: var(--tq-shadow-lg);
  border-color: var(--tq-border);
}

.tq-stat-card--blue    { --tq-card-accent: var(--tq-accent); }
.tq-stat-card--gold    { --tq-card-accent: var(--tq-gold); }
.tq-stat-card--emerald { --tq-card-accent: var(--tq-emerald); }
.tq-stat-card--amber   { --tq-card-accent: var(--tq-amber); }
.tq-stat-card--grey    { --tq-card-accent: var(--tq-grey); }

.tq-stat-card__top { display: flex; align-items: center; justify-content: space-between; margin-bottom: 12px; }

.tq-stat-card__icon {
  width: 34px;
  height: 34px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: color-mix(in srgb, var(--tq-card-accent) 12%, white);
  color: var(--tq-card-accent);
}

.tq-stat-card__icon svg { width: 17px; height: 17px; }

/* عنصر الرقم: يُملأ تلقائيًا عبر dashboard.js إن رغبت بالربط الحي بالبيانات */
.tq-stat-card__value {
  font-size: 24px;
  font-weight: 800;
  color: var(--tq-ink);
  line-height: 1;
  margin-bottom: 4px;
}

.tq-stat-card__value.is-loading { color: var(--tq-ink-faint); }

.tq-stat-card__label { font-size: 12px; color: var(--tq-ink-soft); font-weight: 600; }

/* ============================================================
   بطاقات الأدوات / الاختصارات (Shortcuts المقابلة)
   ============================================================ */
.tq-actions__grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--tq-space-2);
}

.tq-actions__grid--3 { grid-template-columns: repeat(3, 1fr); }

.tq-action {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 9px;
  text-align: center;
  text-decoration: none;
  color: var(--tq-ink);
  background: var(--tq-bg);
  border: 1px solid var(--tq-border);
  border-radius: var(--tq-radius-md);
  padding: 15px 10px;
  cursor: pointer;
  transition: border-color 0.15s ease, box-shadow 0.15s ease, transform 0.15s ease, background 0.15s ease;
}

.tq-action:hover {
  border-color: var(--tq-action-color, var(--tq-accent));
  box-shadow: 0 0 0 4px var(--tq-action-ring, var(--tq-accent-ring));
  background: var(--tq-action-soft, var(--tq-accent-soft));
  transform: translateY(-2px);
}

.tq-action__icon {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: var(--tq-action-soft, var(--tq-accent-soft));
  color: var(--tq-action-color, var(--tq-accent));
  display: flex;
  align-items: center;
  justify-content: center;
}

.tq-action__icon svg { width: 18px; height: 18px; }

.tq-action__label { font-size: 12px; font-weight: 700; color: var(--tq-ink); }

/* ألوان الأدوات حسب حالة العنصر (تطابق ألوان shortcuts الأصلية في الـ Workspace) */
.tq-action--green  { --tq-action-color: var(--tq-emerald); --tq-action-soft: var(--tq-emerald-soft); --tq-action-ring: rgba(31,122,92,.16); }
.tq-action--orange { --tq-action-color: var(--tq-amber);   --tq-action-soft: var(--tq-amber-soft);   --tq-action-ring: rgba(179,121,31,.16); }
.tq-action--yellow,
.tq-action--gold    { --tq-action-color: var(--tq-gold);    --tq-action-soft: var(--tq-gold-soft);    --tq-action-ring: rgba(184,146,63,.16); }
.tq-action--red     { --tq-action-color: var(--tq-red);    --tq-action-soft: var(--tq-red-soft);     --tq-action-ring: rgba(178,58,58,.16); }
.tq-action--blue    { --tq-action-color: var(--tq-accent); --tq-action-soft: var(--tq-accent-soft);  --tq-action-ring: var(--tq-accent-ring); }
.tq-action--grey    { --tq-action-color: var(--tq-grey);   --tq-action-soft: var(--tq-grey-soft);    --tq-action-ring: rgba(90,100,116,.14); }

/* ============================================================
   الاستجابة (Responsive)
   ============================================================ */
@media (max-width: 1100px) {
  .tq-actions__grid,
  .tq-actions__grid--3 { grid-template-columns: repeat(3, 1fr); }
}

@media (max-width: 900px) {
  .tq-stats { grid-template-columns: repeat(2, 1fr); }
}

@media (max-width: 640px) {
  .tq-hero { flex-direction: column-reverse; align-items: flex-start; padding: 28px 20px; }
  .tq-hero__seal { width: 60px; height: 60px; }
  .tq-hero__seal svg { width: 28px; height: 28px; }
  .tq-hero__title { font-size: 21px; }
  .tq-stats { grid-template-columns: 1fr; }
  .tq-actions__grid,
  .tq-actions__grid--3 { grid-template-columns: repeat(2, 1fr); }
  .tq-module__title { font-size: 17px; }
}

script:
// ننتظر حتى ينتهي الـ ERPNext من تحميل محتويات صفحة الـ DOM بالكامل 
document.addEventListener("DOMContentLoaded", function() {

  // 1. منطق التبديل بين التبويبات (Tabs)
  const tabButtons = document.querySelectorAll('.block-root .tab-btn');
  const sections = document.querySelectorAll('.block-root .section');

  tabButtons.forEach(button => {
    button.addEventListener('click', function() {
      const targetTab = this.getAttribute('data-tab');

      // إخفاء كل السكاشن
      sections.forEach(sec => sec.classList.remove('visible'));

      // إلغاء كلاس النشاط من الأزرار
      tabButtons.forEach(btn => btn.classList.remove('active'));

      // إظهار السكشن المختار
      const targetSection = document.getElementById('sec-' + targetTab);
      if (targetSection) {
        targetSection.classList.add('visible');
      }

      // تفعيل الزر المضغوط
      this.classList.add('active');
    });
  });

  // 2. معالجة أحداث الأزرار الفرعية (Actions) والتواصل مع ERPNext
  // زر إضافة نشاط جديد بالأعلى
  const addBtn = document.getElementById('btn-add-activity');
  if (addBtn) {
    addBtn.addEventListener('click', function() {
      // إذا كنت تستخدم الحوارات السريعة في ERPNext، يمكنك استدعاء frappe.new_doc هنا
      if (typeof frappe !== 'undefined') {
        frappe.new_doc('Cultural Activity'); // قم بتغيير اسم الـ DocType لما يناسب نظامك
      } else {
        console.log('طلب إضافة نشاط جديد');
      }
    });
  }

  // أزرار العرض السريع داخل القوائم والجدول
  const actionButtons = document.querySelectorAll('.block-root .quick-action');
  actionButtons.forEach(btn => {
    btn.addEventListener('click', function() {
      const actionType = this.getAttribute('data-action');
      
      if (typeof frappe !== 'undefined') {
        // مثال: التوجيه لـ DocType معين عند الضغط على أزرار الجدول في ERPNext
        frappe.msgprint(__('تم اختيار الإجراء: ') + actionType);
      } else {
        console.log('Action triggered:', actionType);
      }
    });
  });

});

style:
/* إخفاء نصوص القراءة الآلية فقط */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
}

/* إعدادات خطوط والاتجاه العام للبلوك */
* { 
  box-sizing: border-box; 
  margin: 0; 
  padding: 0; 
}

.block-root { 
  direction: rtl; 
  font-family: var(--font-sans), sans-serif; 
  padding: 1rem; 
}

.block-header { 
  display: flex; 
  align-items: center; 
  justify-content: space-between; 
  margin-bottom: 1.25rem; 
}

.block-title { 
  font-size: 18px; 
  font-weight: 600; 
  color: var(--color-text-primary, #111827); 
}

.block-subtitle { 
  font-size: 13px; 
  color: var(--color-text-secondary, #6b7280); 
  margin-top: 2px; 
}

/* أزرار التبويبات (Tabs) */
.tab-row { 
  display: flex; 
  gap: 8px; 
  margin-bottom: 1.25rem; 
  flex-wrap: wrap; 
}

.tab-btn { 
  font-size: 13px; 
  padding: 8px 16px; 
  border-radius: var(--border-radius-md, 6px); 
  border: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  background: transparent; 
  color: var(--color-text-secondary, #6b7280); 
  cursor: pointer; 
  transition: all 0.15s ease-in-out; 
}

.tab-btn.active { 
  background: var(--color-background-secondary, #f3f4f6); 
  color: var(--color-text-primary, #111827); 
  border-color: var(--color-border-primary, #9ca3af); 
  font-weight: 500; 
}

.tab-btn:hover:not(.active) { 
  background: var(--color-background-secondary, #f3f4f6); 
}

/* الأقسام المخفية والظاهرة */
.section { 
  display: none; 
}

.section.visible { 
  display: block; 
}

/* لوحة الإحصائيات السريعة */
.stats-grid { 
  display: grid; 
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); 
  gap: 12px; 
  margin-bottom: 1.5rem; 
}

.stat-card { 
  background: var(--color-background-secondary, #f9fafb); 
  border-radius: var(--border-radius-md, 6px); 
  padding: 1rem; 
  border: 1px solid var(--color-border-tertiary, #f3f4f6);
}

.stat-label { 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
  margin-bottom: 6px; 
}

.stat-value { 
  font-size: 24px; 
  font-weight: 600; 
  color: var(--color-text-primary, #111827); 
}

.stat-change { 
  font-size: 11px; 
  margin-top: 4px; 
}

.stat-change-neutral {
  font-size: 11px; 
  margin-top: 4px;
  color: var(--color-text-secondary, #9ca3af);
}

.up { color: #1D9E75; } 
.down { color: #D85A30; }

/* تصميم قائمة البطاقات (الكادر الدعوي) */
.card-list { 
  display: flex; 
  flex-direction: column; 
  gap: 10px; 
}

.card-item { 
  background: var(--color-background-primary, #ffffff); 
  border: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  border-radius: var(--border-radius-lg, 8px); 
  padding: 1rem; 
  display: flex; 
  align-items: center; 
  gap: 14px; 
  transition: border-color 0.15s; 
}

.card-item:hover { 
  border-color: var(--color-border-secondary, #d1d5db); 
}

.card-avatar { 
  width: 40px; 
  height: 40px; 
  border-radius: 50%; 
  display: flex; 
  align-items: center; 
  justify-content: center; 
  font-size: 14px; 
  font-weight: 500; 
  flex-shrink: 0; 
}

.av-blue { background: #E6F1FB; color: #185FA5; }
.av-teal { background: #E1F5EE; color: #0F6E56; }
.av-amber { background: #FAEEDA; color: #854F0B; }
.av-coral { background: #FAECE7; color: #993C1D; }

.card-info { 
  flex: 1; 
  min-width: 0; 
}

.card-name { 
  font-size: 14px; 
  font-weight: 500; 
  color: var(--color-text-primary, #111827); 
}

.card-meta { 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
  margin-top: 2px; 
  white-space: nowrap; 
  overflow: hidden; 
  text-overflow: ellipsis; 
}

.card-badge { 
  font-size: 11px; 
  padding: 4px 12px; 
  border-radius: var(--border-radius-md, 6px); 
  flex-shrink: 0; 
}

.badge-success { background: #E1F5EE; color: #0F6E56; }
.badge-warn { background: #FAEEDA; color: #854F0B; }
.badge-info { background: #E6F1FB; color: #185FA5; }
.badge-muted { background: var(--color-background-secondary, #f3f4f6); color: var(--color-text-secondary, #6b7280); }

/* القائمة السريعة للأنشطة */
.quick-list { 
  display: flex; 
  flex-direction: column; 
}

.quick-item { 
  display: flex; 
  align-items: center; 
  gap: 12px; 
  padding: 12px 0; 
  border-bottom: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
}

.quick-item:last-child { 
  border-bottom: none; 
}

.quick-icon { 
  width: 34px; 
  height: 34px; 
  border-radius: var(--border-radius-md, 6px); 
  display: flex; 
  align-items: center; 
  justify-content: center; 
  flex-shrink: 0; 
}

.quick-text { 
  flex: 1; 
  font-size: 13px; 
  color: var(--color-text-primary, #111827); 
}

.quick-detail { 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
}

.quick-action { 
  font-size: 11px; 
  color: var(--color-text-secondary, #6b7280); 
  padding: 4px 12px; 
  border: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  border-radius: var(--border-radius-md, 6px); 
  cursor: pointer; 
  background: transparent; 
  transition: background 0.15s; 
  white-space: nowrap; 
}

.quick-action:hover { 
  background: var(--color-background-secondary, #f3f4f6); 
}

/* جدول المراكز */
.mini-table { 
  width: 100%; 
  border-collapse: collapse; 
  font-size: 13px; 
}

.mini-table th { 
  text-align: right; 
  font-weight: 500; 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
  padding: 0 0 10px; 
  border-bottom: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
}

.mini-table td { 
  padding: 12px 0; 
  border-bottom: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  color: var(--color-text-primary, #111827); 
  vertical-align: middle; 
}

.mini-table tr:last-child td { 
  border-bottom: none; 
}

.mini-table td:last-child, 
.mini-table th:last-child { 
  text-align: left; 
}

.product-title { font-weight: 500; }
.sku { color: var(--color-text-secondary, #6b7280); font-size: 11px; }

/* نقاط المراقبة الملونة */
.dot { 
  width: 8px; 
  height: 8px; 
  border-radius: 50%; 
  display: inline-block; 
  margin-left: 6px; 
  vertical-align: middle; 
}

.dot-green { background: #1D9E75; } 
.dot-amber { background: #BA7517; } 
.dot-red { background: #D85A30; }

/* أزرار الإجراء الرئيسية الأعلى */
.add-btn { 
  display: flex; 
  align-items: center; 
  gap: 6px; 
  font-size: 13px; 
  padding: 8px 16px; 
  border-radius: var(--border-radius-md, 6px); 
  border: 0.5px solid var(--color-border-secondary, #d1d5db); 
  background: transparent; 
  color: var(--color-text-primary, #111827); 
  cursor: pointer; 
  transition: background 0.15s; 
}

.add-btn:hover { 
  background: var(--color-background-secondary, #f3f4f6); 
}
